var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"있을 수 없어요. 관리국 시기와 비교해도 손색없는 최상급의 시큐리티 시스템인데…!","JPN":"こんなのありえません。管理局の時代と比べても遜色ない最上級のセキュリティシステムなのに……！","ENG":"Impossible! Even compared to the Administration times, this is the best security system...!","TWN":"怎麼可能，這可是和管理局時期相比，也毫不遜色的最頂級安全系統…！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"카운터도 아닌 분에게 돌파당하다니…….","JPN":"カウンターでもない方に突破されるなんて……","ENG":"How could someone who isn't even a Counter break through...?","TWN":"竟然會遭到非制裁者的人突破……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저 역시 사활을 걸고 임했기에 행운이 따른 점, 부디 이해해 주시길.","JPN":"私も死ぬ気で戦って運が向いたことをどうかご理解ください。","ENG":"Please understand that I risked my life and luck favored me.","TWN":"我也是賭上性命來的，才有這樣的好運氣，還請見諒。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이렇게 심각한 부상을 입은 건……. 무척 오랜만이랍니다.","JPN":"これほどに深刻な怪我を負ったのは……かなり久しぶりです。","ENG":"But it's been a long time since... I got wounded this badly.","TWN":"我也很久……沒受到這麼嚴重的傷。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"멈추세","JPN":"やめてくだ","ENG":"Miss Vero","TWN":"住"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"요, 베로니카","JPN":"さい、ベロニカ","ENG":"nica, stop!","TWN":"手，貝洛"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":" 씨!","JPN":" さん！","ENG":" Please","TWN":"妮卡！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"다시 생각해 보세요. 관리자님이","JPN":"もう一度考え直してください。管理者様が","ENG":" reconsider! You know the Administrator","TWN":"你再想一想，管理者"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":" 괜히 그런 말씀을 남기셨을 리 없잖아요.","JPN":" 何の意味もなくあの言葉を残したはずがありません。","ENG":" wouldn't have said that for no reason.","TWN":"不會沒有理由就留下那段話的。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님과 뜻을 함께하는 분들이 허수 공간에 갇혀 계시다고 하더군요.","JPN":"ご主人様と同じ志をお持ちの方々が虚数空間に閉じ込められているらしいですね。","ENG":"I heard that Master's followers were trapped in the imaginary space.","TWN":"我聽說和主人志同道合的人，現在都被困在虛數空間裡。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"클리포트 게임이란 것에서 승리하려면 그 분들이 꼭 필요함에도 불구하고.","JPN":"クリフォトゲームというものに勝利するためには、その方々が必ず必要であるにもかかわらず。","ENG":"Despite the fact that they are required to win the Qliphoth Game.","TWN":"明明若要在逆卡巴拉遊戲中取得勝利，是非他們不可的。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 이야기가 사실인가요, 모네카 씨?","JPN":"本当でしょうか？　モネカさん。","ENG":"Is that true, Miss Moneka?","TWN":"這是真的嗎，莫奈卡？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"뭐, 뭔가 잘못 아신 거겠죠. 일반적으로 허수 공간에 들어가는 건 자살 행위라고요.","JPN":"な、何かの間違いでしょう。一般的に虚数空間に入るのは自殺行為ですもの。","ENG":"I-I think you misheard. Entering the imaginary space is normally a suicide mission.","TWN":"這…有什麼誤會吧？基本上，進到虛數空間無疑是自殺行為。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"클리포트 게임에 대해선 부정하지 않으시는군요.","JPN":"クリフォトゲームについては否定しないのですね。","ENG":"But you don't seem to deny the part about the Qliphoth Game.","TWN":"你沒有否認逆卡巴拉遊戲的部分。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"우웃…….","JPN":"ううっ……","ENG":"Ngh...","TWN":"唔……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그건…. 베로니카 씨를 위해서라도 말씀드릴 수 없어요.","JPN":"それは……ベロニカさんのためにもお話しできません。","ENG":"I... cannot tell you that for your own sake, Miss Veronica.","TWN":"這…恕我無可奉告，貝洛妮卡，我是為你好。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"사실이라는 뜻으로 이해하겠습니다.","JPN":"本当だということで理解しましょう。","ENG":"I'll assume that it is true, then.","TWN":"那我就當你是默認了。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"잠깐, 잠깐만요! 회사 직원 분들이랑 델타 세븐 분들이 허수 공간에 갇힌 건 맞지만요!","JPN":"ちょっ、ちょっと待ってください！　会社の職員とデルタセブンの方が虚数空間に閉じ込められているのは本当ですけど！","ENG":"W-wait! It is true that our employees and Delta Seven are trapped inside the imaginary space, but...!","TWN":"等等，先等一下！公司的員工和第七三角洲部隊的人，確實是困在虛數空間裡沒錯！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"저 안은 위험해요. 평범한 인간이 들어갈 수 있는 곳이 절대 아니라고요.","JPN":"あの中は危険なんです。絶対普通の人間が入れるような場所ではありません。","ENG":"That room is dangerous. It's not a place that normal person can enter.","TWN":"但那裡面非常危險，那不是普通人可以進去的地方！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 눈에는 그저 복잡한 기계장치가 가득찬 곳으로만 보이는데…. 어째서죠?","JPN":"私にはただ複雑な装置が詰まったところにしか見えませんが……どうしてですか？","ENG":"All I see is a room filled with complicated devices... Why would that be the case?","TWN":"怎麼辦呢…？在我看來，那裡不過就是充滿許多複雜機械裝置的地方。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이 문턱 너머는 고심도 이면세계나 다름없는 환경이에요!","JPN":"この扉の向こうは高深度の裏世界と何ら変わらない環境なんです！","ENG":"Because the environment just beyond this point is identical to the hyperdepths of Counterside!","TWN":"這扇門另一邊的空間，跟高深度異界沒二樣！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"공간의 균열에서 고준위 침식","JPN":"空間の亀裂から高レベルの侵食","ENG":"High-level Corruption ray flows","TWN":"高侵蝕波正從空間的裂縫"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"파가 유입되고 있어요. 관리자님","JPN":"波が流入しています。管理者様","ENG":" through the cracks made by the rift. We ar","TWN":"流入。管理者"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"께서 회수한 테라브레인들이 중화해 주고 있지만….","JPN":"が回収したテラブレインたちが中和してくれてますけど……","ENG":"e purifying it with the Terrabrain the Administrator retrieved, but...","TWN":"回收的特拉大腦正在緩解…"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"결국에는 새로운 대균열의 발생을 막기 위한 임시방편에 지나지 않아요.","JPN":"結局は新しい大亀裂の発生を防ぐためのその場しのぎに過ぎません。","ENG":"In the end, it's only a temporary measure to prevent another Grand Dimension Crevice from opening.","TWN":"但結果而言，不過是防止產生新裂縫的權宜之計。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"카운터도 물리적인 격통을 느낄 정도라고요!","JPN":"カウンターでも物理的な激痛を感じるくらいなんですよ！","ENG":"It's potent enough for even a Counter to feel physical pain!","TWN":"連制裁者都會感受到無比的痛楚！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"괜찮습니다. 저에게 통각이란 생경한 것이 되었으니까요.","JPN":"大丈夫です。私に痛覚というものはありませんから。","ENG":"It's all right. Pain has become foreign to me.","TWN":"沒關係，我早就不知道痛為何物。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"침식 증후군은요? 잠시 들어가기만 해도 광증이 나타날 수도 있어요!","JPN":"侵食症候群は？　ちょっと入っただけでも狂気になるかもしれません！","ENG":"Then what about the Corruption Syndrome? Just stepping inside there could cause you to go insane!","TWN":"那侵蝕症候群呢？就算只進去一下，也很可能會發作的！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"걱정해 주셔서 감사합니다.","JPN":"ご心配いただきありがとうございます。","ENG":"Thank you for worrying about me.","TWN":"謝謝你替我擔心。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 주인님께서 하시는 일은 저희 모두를 위한 것이라고 믿기에……","JPN":"ですがご主人様のなさることは、すべて私たちのためと信じておりますので……","ENG":"But I trust that Master's work is for the sake of all of us, so...","TWN":"不過，我相信主人所做的一切都是為了我們……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 한 몸 바칠 각오는 일찍이 하고 있었답니다.","JPN":"この身を捧げる覚悟はすでにできていたのです。","ENG":"I've always been ready to do my part as well.","TWN":"因此我早就做好奉獻生命的心理準備。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ff3636>Q. 일반인이 고준위 침식파에 노출되면 어떻게 됩니까?</color>","JPN":"<color=#ff3636>Q. 一般人が高レベルの侵食波に晒された場合どうなりますか？</color>","ENG":"<color=#ff3636>Q. What happens when a non-Counter is exposed to high-level Corruption ray?</color>","TWN":"<color=#ff3636>Q. 普通人暴露在高侵蝕波底下會發生什麼事？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ff3636>A. 먼저 환청, 환각 같은 정신이상 증세가 나타납니다.</color>","JPN":"<color=#ff3636>A. まずは幻聴、幻覚のような精神異常の症状が起こります。</color>","ENG":"<color=#ff3636>A. First of all, they have visual and auditory hallucinations.</color>","TWN":"<color=#ff3636>A. 首先會發生幻聽，或幻覺這種疑似精神失常的症狀。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ff3636>Q. 그런데 이 여자는 왜 스스로 죽으려고 하죠?</color>","JPN":"<color=#ff3636>Q. でもこの女はどうして自ら死のうとしているのですか？</color>","ENG":"<color=#ff3636>Q. Then why is this girl trying to get herself killed?</color>","TWN":"<color=#ff3636>Q. 那這個女人為何要自尋死路呢？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ff3636>A. 글쎄요? 살기가 싫어졌나 보죠!</color>","JPN":"<color=#ff3636>A. さあ？　生きるのが嫌になったのかもしれません！</color>","ENG":"<color=#ff3636>A. Who knows? Maybe she just doesn't want to live anymore.</color>","TWN":"<color=#ff3636>A. 這個嘛，應該是活膩了吧！!</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>뱃속이 썩어 들어가는 것 같아.</color>","JPN":"<color=#ff3636>腹の中が腐っていくようです。</color>","ENG":"<color=#ff3636>I feel like my insides are rotting.</color>","TWN":"<color=#ff3636>肚子裡似乎正在腐壞。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>이대로는 몇 발자국 못 가서 피를 토하고 주저앉겠지.</color>","JPN":"<color=#ff3636>このままでは数歩も行かずに血を吐いて倒れるでしょう。</color>","ENG":"<color=#ff3636>At this rate, I'll be throwing up blood before making it all the way over there.</color>","TWN":"<color=#ff3636>這樣下去可能沒走幾步路就會吐血身亡。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……상관없습니다.","JPN":"……構いません。","ENG":"...It doesn’t matter.","TWN":"……無所謂。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>사실은 무섭습니다. 침식파로 죽는 사람의 최후가 얼마나 꼴사나운지 알고 있으니까.</color>","JPN":"<color=#ff3636>実は怖いのです。侵食波で死ぬ人の最期がどれほど醜いか知っているから。</color>","ENG":"<color=#ff3636>Truthfully, I'm scared. Because I know how ugly the end is for a person who dies from Corruption ray.</color>","TWN":"<color=#ff3636>其實我很害怕，我很清楚因爲侵蝕波而死亡的人，死前的模樣有多醜陋。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>스스로 설 수 없을 지경이 되어, 땅바닥을 기어다니면서 차라리 어서 죽여 주길 기원하겠죠.</color>","JPN":"<color=#ff3636>ひとりでは立てなくなって、地べたをはいずり回りながら、いっそのこと殺してくれと願うことになるでしょう。</color>","ENG":"<color=#ff3636>I'm sure I'll beg for death as my legs give out and I crawl on the floor.</color>","TWN":"<color=#ff3636>無法自行站立，必須在地上爬，恨不得求一個痛快。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"무섭지 않습니다. 주인님께 도움을 드릴 수만 있다면.","JPN":"怖くありません。ご主人様のお役に立てるのならば。","ENG":"I'm not afraid. So long as I can assist Master.","TWN":"我不怕，只要能夠幫到主人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>상처가 나 있으면 침식파에 영향을 더 심하게 받습니다.</color>","JPN":"<color=#ff3636>傷があると侵食波の影響はより深刻です。</color>","ENG":"<color=#ff3636>Being wounded increases the effectiveness of the Corruption ray.</color>","TWN":"<color=#ff3636>若是有傷口，侵蝕波對我的影響就會越劇烈。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>흉측하게 일그러져도 주인님이 날 받아들여 줄까? 경멸하고 버리시지 않을까?</color>","JPN":"<color=#ff3636>凶悪に歪んだ姿でもご主人様は私を受け入れてくださるでしょうか？　軽蔑してお捨てになるのでは？</color>","ENG":"<color=#ff3636>Will Master still accept me even if I'm hideous? Won't he despise me and throw me away?</color>","TWN":"<color=#ff3636>我變得那麼醜陋的話，主人還會接納我嗎？他會不會瞧不起我就拋棄我？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께서 제가 바라는 대로만 해 주시길 바라는 것도, 메이드로서는 아집입니다.","JPN":"ご主人様に私の望むがままに行動してくださるように願うことは、メイドとしてあるまじきことです。","ENG":"It's selfish for a maid to want her master to do as she pleases.","TWN":"希望主人對我言聽計從，這是身為女僕的奢望。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ff3636>입에서 피 흐르는 거 안 보여?</color>","JPN":"<color=#ff3636>口から血が流れてるでしょう？</color>","ENG":"<color=#ff3636>Is this blood trickling down my mouth?</color>","TWN":"<color=#ff3636>沒看到嘴巴在流血嗎？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ff3636>카운터도 아니잖아요. 왜 저는 계속 나대는 거죠? 제가 대체 뭔데요?</color>","JPN":"<color=#ff3636>カウンターでもないくせに。差し出がましく何ですか？　私がいったい何者だというのですか？</color>","ENG":"<color=#ff3636>I'm not even a Counter. Why am I even insisting on doing this? How dare I?</color>","TWN":"<color=#ff3636>我又不是制裁者，為什麼要一直淌渾水？我算什麼東西？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>살인자! 살인자! 살인자!</color>","JPN":"<color=#ff3636>人殺し！　人殺し！　人殺し！</color>","ENG":"<color=#ff3636>Murderer! Murderer! Murderer!</color>","TWN":"<color=#ff3636>殺人犯！殺人犯！殺人犯！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>나는 캄캄한 땅속에서 아무도 모르게 뒈져 버릴 거야! 아무 도움도 받지 못하고 비참하게!</color>","JPN":"<color=#ff3636>私は暗い土の中で誰にも知られずのたれ死ぬのよ！　助けもなく惨めにね！</color>","ENG":"<color=#ff3636>I'm going to die in this dark hole without anyone knowing! Miserably and all by myself!</color>","TWN":"<color=#ff3636>我會默默死在黑暗的地裡！沒人幫我！淒慘無比！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"베로니카 양.","JPN":"ベロニカ。","ENG":"Veronica.","TWN":"貝洛妮卡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"이제 그만하게. 여기 오래 있으면 얼마 가지 못해 영영 눈을 뜨지 못할 거야.","JPN":"もうやめたまえ。ここに長くいたら永遠に目覚められなくなってしまうぞ。","ENG":"Enough. You know how this will end if you stay here any longer.","TWN":"到此為吧，在這裡待太久的話，我怕你會永遠爭不開眼睛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"환상이군요.","JPN":"幻想ですね。","ENG":"It's an illusion.","TWN":"原來是幻覺。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"환상이라니 무슨 말인가. 자네가 무모한 행동을 하기에 급히 온 거란 말일세.","JPN":"幻想とは何だ？　君が無茶な行動をしているから急いで駆けつけたんじゃないか。","ENG":"An illusion? I came here because you are being reckless.","TWN":"你在胡說什麼，這不是幻覺，我知道你這麼衝動後才急忙趕來的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"나에게는 자네가 필요해. 동료나 부하가 아니라, 평생의 동반자로서.","JPN":"私には君が必要だ。仲間や部下としてではなく、人生の伴侶として。","ENG":"I need you. Not as an employee or a colleague, but as my lifelong companion.","TWN":"我需要你，不是需要你當我同事或下屬，而是當我終身的伴侶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"듣기 좋아할 말들만 해 주셔서 감사합니다.","JPN":"聞いて喜びそうな言葉ばかりくださり、ありがとうございます。","ENG":"Thank you for saying what I'd like to hear.","TWN":"謝謝主人說這種話討我開心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 주인님께서는 자신이 짊어지신 것들을 쉽게 내칠 분이 아니세요.","JPN":"ですが、ご主人様はご自分が負っているものをそう易々と放りだすような方ではありません。","ENG":"But the Master I know would never give up his duties that easily.","TWN":"不過主人不是會輕易卸下肩頭重擔的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"직원 분들과 저, 둘 중 하나를 선택해야 한다면 아픔을 무릅쓰고 전자를 택하시겠죠.","JPN":"職員と私、二つのうち一つを選択しなければならない状況でしたら、痛みに堪えてでも前者をお選びになるでしょう。","ENG":"If you were to choose between your employees and me, I know you would choose the former no matter how much it hurt.","TWN":"若是要在員工和我之間做出選擇，主人一定會忍痛選擇前者的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 내가 싫지 않나? 나에게는 자네만 있으면 돼!","JPN":"そういう私は嫌だろう？　私には君さえいれば十分だ！","ENG":"I know you don't like that about me. But all I need is you!","TWN":"不覺得那樣的我很討厭嗎？我只要你！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 분의 삶을 스쳐 지나간 기억으로만 남을지라도, 저에게는 충분한 호사입니다.","JPN":"あの方の人生において、すれ違った程度の記憶でしか残らなかったとしても、私には身に余る贅沢です。","ENG":"Even if I was just a passing memory in his life, it was more than I deserved.","TWN":"只要能夠在他的生命中留下一絲記憶，我便心滿意足。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>이 빌어먹을 년아! 네 상처에서 벌레가 기어나오는 것 안 보여?!</color>","JPN":"<color=#ff3636>なんて女なんだ！　君の傷口から虫が這い出てくるのが見えないのか！？</color>","ENG":"<color=#ff3636>Hey idiot! Don't you see the maggots coming out from your wound?!</color>","TWN":"<color=#ff3636>你這臭女人！沒看到你的傷口裡爬滿蟲嗎？！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L38_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ff3636>넌 쓸모없어! 귀찮게 엉겨붙기나 하고! 아무데로나 좀 꺼져 버리라고!</color>","JPN":"<color=#ff3636>君は役に立たないな！　纏わりついてばかりで！　どこかに行ってくれないか！</color>","ENG":"<color=#ff3636>You're useless! Always being needy! Go away!</color>","TWN":"<color=#ff3636>你已經是個廢人！還敢纏著我不放！你給我滾！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>더러운 살인자 년! 용서고 속죄고 전부 가식이지! 이 역겨운 년!!</color>","JPN":"<color=#ff3636>汚い人殺しめ！　許しも贖罪も全部偽りなんだろう！　吐き気がする！！</color>","ENG":"<color=#ff3636>Filthy murderer! All your atonement was fake! You're nothing but a disgusting hypocrite!!</color>","TWN":"<color=#ff3636>骯髒的殺人兇手！什麼饒恕還贖罪，都是假的吧！你這噁心的女人！！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……주인님의 목소리로 듣는 힐난은 견디기가 어렵군요.","JPN":"……ご主人様の声で聞く責めの言葉は耐えがたいですね。","ENG":"...It's difficult to bear the accusations when it's in your voice, Master.","TWN":"……聽到主人的聲音說出這種話還真煎熬。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 정신적인 압박은 자백제에 내성을 기르는 훈련을 통해 충분히 경험해 봤습니다.","JPN":"ですが精神的な圧迫は自白剤への耐性を養う訓練を通じて十分経験しました。","ENG":"I've been trained, however, not to crack under mental duress when developing a resistance to truth serums.","TWN":"不過在培養對自白劑的抗藥性時，已經針對這種精神上的壓迫進行過充分的訓練。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>세계 관리국 제 1 관리 대행자.</color>","JPN":"<color=#ffd34c>世界管理局第1管理代行者。</color>","ENG":"<color=#ffd34c>World Administration 1st Management Agent.</color>","TWN":"<color=#ffd34c>世界管理局第1管理代理人。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_RAZANGRIFF_SKILL_START"},{"id":"L45_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>테크 레벨 6 하이브 컨트롤. 대기 중.</color>","JPN":"<color=#ffd34c>テックレベル6 ハイブコントロール。待機中。</color>","ENG":"<color=#ffd34c>Tech Level 6 Hive Control. On standby.</color>","TWN":"<color=#ffd34c>技術等級6 巢穴控制系統待機中。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"콜록…….","JPN":"ゲホッ……","ENG":"*Cough...*","TWN":"咳咳……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"장기에 문제가 생기기 시작했군요. 남은 시간이 얼마 없겠어요.","JPN":"内臓に問題が発生し始めましたね。残り時間は僅かのようです。","ENG":"My organs are starting to fail. It seems I don't have much time.","TWN":"體內器官似乎開始產生問題，看來時間所剩不多。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>공간 안정성 강화. 침식파 유입 차단.</color>","JPN":"<color=#ffd34c>空間の安定性を強化。侵食波の流入を遮断。</color>","ENG":"<color=#ffd34c>Enhancing spatial stability. Blocking the inflow of the Corruption ray.</color>","TWN":"<color=#ffd34c>強化空間穩定性，隔絕侵蝕波流入。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모조 차원계면 형성 중단. 방호 프로세스로 이행합니다.</color>","JPN":"<color=#ffd34c>模造次元界面の形成を中断。防護プロセスに移行します。</color>","ENG":"<color=#ffd34c>Pseudo dimension surface creation discontinued. Initiating Protection process.</color>","TWN":"<color=#ffd34c>停止形成仿造次元界面，執行防護程序。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이제 남은 건…. 패널을 조작해서 암호를 입력하면….","JPN":"後は……パネルを操作してパスワードを入力すれば……","ENG":"Now, all that's left... is to enter the password with the panel...","TWN":"最後是…操作面板輸入密碼後…"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>ERROR. 프로세스 이행을 위한 동력이 부족합니다.</color>","JPN":"<color=#ffd34c>ERROR。プロセスに移行するための動力が不足しています。</color>","ENG":"<color=#ffd34c>ERROR. Not enough power to proceed.</color>","TWN":"<color=#ffd34c>ERROR，動能不足無法執行程序。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"동력 부족이라고요? 어째서……?","JPN":"動力不足？　どうして……？","ENG":"Not enough power? But why...?","TWN":"動能不足嗎？怎麼會……？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>베로니카 씨, 조심하세요!</color>","JPN":"<color=#ffd34c>ベロニカさん！　気をつけてください！</color>","ENG":"<color=#ffd34c>Miss Veronica! Look out!</color>","TWN":"<color=#ffd34c>貝洛妮卡，小心！</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"총격? 환각이 아니야?","JPN":"銃撃？　幻覚ではない？","ENG":"A bullet? This one's not an illusion?!","TWN":"有人開槍？是幻覺嗎？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그 낡은 건물 밑에 이런 공간이 있을 줄은 몰랐어.","JPN":"古い建物の下にこんな空間があるとはな。","ENG":"Who knew something like this would be below this crumbling building.","TWN":"沒想到這麼老舊的建築物底下，竟然會有這種空間。"},"stage":{"bg":"LIFT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"찾았다. 베로니카.","JPN":"見つけたよ、ベロニカ。","ENG":"Gotcha. Veronica.","TWN":"找到你囉，貝洛妮卡。"},"stage":{"bg":"LIFT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…민병대 분이시군요. 어떻게 이 먼 곳까지 오셨습니까?","JPN":"……民兵隊の方ですね。どうやってこのように遠いところまでいらしたのですか？","ENG":"It's you, the Militia... How did you make it all the way here?","TWN":"…原來是民兵隊的人，遠道而來所為何事呢？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지 말아야 할 짓만 골라서 했다고 해 두지.","JPN":"してはいけないことばかりをした、とだけ言っておこう。","ENG":"Let's just say we did stuff we weren't supposed to in order to get here.","TWN":"就當我喜歡找自己麻煩吧。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"밖이 어수선하던데, 그쪽이 벌인 짓인가?","JPN":"外が騒がしいが、あんたのせいか？","ENG":"It seems rowdy outside. Is that your doing?","TWN":"我看外面一團亂，是你幹的好事嗎？?"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"송구스럽지만 그렇습니다. 때로는 적이 아니더라도 대립하게 되는 경우가 있죠.","JPN":"申し訳ありませんが、そのとおりです。時には敵でなくても対立する場合があります。","ENG":"I'm ashamed to admit it, but yes. At times, even if they aren't the enemy, confrontation is unavoidable.","TWN":"抱歉，是我沒錯。有時候，就算不是敵人也會有對立的情況發生。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"마지막으로 기회를 주겠어. 베로니카.","JPN":"最後にチャンスを与えてやる。ベロニカ。","ENG":"This is your last chance, Veronica.","TWN":"我再給你最後一次機會，貝洛妮卡。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대답해. 맨션의 도움을 받아서 여기 온 거냐?","JPN":"答えろ。マンションの協力を得てここに来たのか？","ENG":"Answer me. Did Mansion help you get here?","TWN":"回答我，你是在曼森的協助下來到這裡的嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"어째서 왔는지 말씀드려도 여러분께는 변명으로만 들리겠죠.","JPN":"どうして来たのかをお話ししても、皆さんには言い訳にしか聞こえないでしょう。","ENG":"No matter what I say, it will all sound like an excuse to you all.","TWN":"就算我告訴你們，在你們聽起來也像是狡辯吧。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 그들의 지원으로 저는 이 자리에 서 있습니다.","JPN":"はい。彼らの協力により私はこの場に立っています。","ENG":"Yes. I did receive help from Mansion.","TWN":"沒錯，我是在他們的協助下站在這裡的。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…차라리 잡아떼면 마음 편했을 텐데.","JPN":"……嘘をついてくれた方が気が楽だったのに。","ENG":"...It would've been better if you'd just denied it.","TWN":"…你隨便找個藉口，我心裡都好過一些。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼 베로니카, 이제부터 너를…….","JPN":"それではベロニカ、今からお前を……","ENG":"Now, Veronica, we are going to...","TWN":"貝洛妮卡，接下來……"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"사냥해 주겠어.","JPN":"狩ってやる。","ENG":"Hunt you.","TWN":"我要獵殺你！"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"무고한 분들의 생명을 수없이 빼앗았으니 심정은 이해합니다.","JPN":"罪のない方々の命を数多く奪ってきましたので、そのお心はわかります。","ENG":"I understand. As I've taken countless lives of innocent people.","TWN":"畢竟我奪走無數無辜的生命，所以可以明白你的心情。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 저도 소임을 다하고자 적과 손을 잡은 몸.","JPN":"ですが私も務めを果たすために敵と手を組んだ身。","ENG":"However, I have also joined hands with the enemy to fulfill my duties.","TWN":"但我也有要完成使命才和會敵人聯手，"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"순순히 사냥감이 되어 드릴 수는 없습니다.","JPN":"素直に獲物になるわけにはいきません。","ENG":"Thus, I won't be an easy prey to hunt.","TWN":"請恕我無法乖乖地成為你的獵物。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};